mapper.select:
SELECT a.*, c.CPNY_LOCATION AS COMPANY_NAME, gvi.CONTENT AS ITEM_NAME_VI, gen.CONTENT AS ITEM_NAME_EN, gzh.CONTENT AS ITEM_NAME_ZH, gko.CONTENT AS ITEM_NAME_KO FROM AR_ITEM_PARAM a LEFT JOIN HR_COMPANY c ON a.CPNY_ID = c.CPNY_ID LEFT JOIN AR_ITEM ai ON a.ITEM_NO = ai.ITEM_NO LEFT JOIN SY_GLOBAL_NAME gvi ON a.ITEM_NO = gvi.NO AND gvi.LANGUAGE = 'vi' LEFT JOIN SY_GLOBAL_NAME gen ON a.ITEM_NO = gen.NO AND gen.LANGUAGE = 'en' LEFT JOIN SY_GLOBAL_NAME gzh ON a.ITEM_NO = gzh.NO AND gzh.LANGUAGE = 'zh' LEFT JOIN SY_GLOBAL_NAME gko ON a.ITEM_NO = gko.NO AND gko.LANGUAGE = 'ko' WHERE a.CPNY_ID = #{cpnyId}
AND a.ITEM_NO = #{itemNo}
ORDER BY a.ORDERNO, a.AR_PARAM_NO

mapper.update:
UPDATE AR_ITEM_PARAM
GROUP_NO = #{groupNo, jdbcType=VARCHAR}, UNIT_VALUE = #{unitValue, jdbcType=NUMERIC}, MIN_VALUE = #{minValue, jdbcType=NUMERIC}, MAX_VALUE = #{maxValue, jdbcType=NUMERIC}, DEPEND_ITEM = #{dependItem, jdbcType=VARCHAR}, REPLACE_ITEM = #{replaceItem, jdbcType=VARCHAR}, CARD_FLAG = #{cardFlag, jdbcType=NUMERIC}, CARD_FROM_FLAG = #{cardFromFlag, jdbcType=NUMERIC}, CARD_FROM_OFFSET = #{cardFromOffset, jdbcType=NUMERIC}, CARD_FROM_RELATION = #{cardFromRelation, jdbcType=VARCHAR}, CARD_TO_FLAG = #{cardToFlag, jdbcType=NUMERIC}, CARD_TO_OFFSET = #{cardToOffset, jdbcType=NUMERIC}, CARD_TO_RELATION = #{cardToRelation, jdbcType=VARCHAR}, APPLY_FLAG = #{applyFlag, jdbcType=NUMERIC}, APPLY_TYPE = #{applyType, jdbcType=VARCHAR}, APPLY_FULLDAY_VALUE = #{applyFulldayValue, jdbcType=NUMERIC}, APPLY_CARD_PRIORITY = #{applyCardPriority, jdbcType=NUMERIC}, DATE_TYPE = #{dateType, jdbcType=VARCHAR}, CPNY_ID = #{cpnyId, jdbcType=VARCHAR}, ITEM_NO = #{itemNo, jdbcType=VARCHAR}, UNIT = #{unit, jdbcType=VARCHAR}, DETAIL_CONTENT = #{detailContent, jdbcType=VARCHAR}, ACTIVITY = #{activity, jdbcType=NUMERIC}, ORDERNO = #{orderno, jdbcType=NUMERIC}, UPDATE_DATE = SYSDATE, UPDATED_BY = #{adminID, jdbcType=VARCHAR}
WHERE AR_PARAM_NO = #{arParamNo}
